import React, { useState } from 'react';
import { View, Button, Alert } from 'react-native';
import WebView from 'react-native-webview';

const NaverLogin = () => {
  const [showWebView, setShowWebView] = useState(false);
  const CLIENT_ID = 'M0Z_vtlzGvZMv9VU2eFj';
  const REDIRECT_URL = 'http://192.168.1.102:19006'; // 네이버 개발자 센터에서 설정한 redirect URL

  const handleNaverLogin = () => {
    setShowWebView(true);
  };

  const handleWebViewNavigationStateChange = (webViewState) => {
    const { url } = webViewState;

    if (url.includes('access_token=')) {
      const token = url.split('access_token=')[1].split('&')[0];
      Alert.alert('네이버 로그인 성공', `Access Token: ${token}`);
      setShowWebView(false);
    }
  };

  return (
    <View style={{ flex: 1 }}>
      {showWebView ? (
        <WebView
          source={{ uri: `https://nid.naver.com/oauth2.0/authorize?response_type=token&client_id=${CLIENT_ID}&redirect_uri=${REDIRECT_URL}&state=YOUR_RANDOM_STATE` }}
          onNavigationStateChange={handleWebViewNavigationStateChange}
          style={{ flex: 1 }}
        />
      ) : (
        <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
          <Button title="네이버 로그인" onPress={handleNaverLogin} />
        </View>
      )}
    </View>
  );
}

export default NaverLogin;
